  if (!coupon) return "";
  const discountType = coupon.discount_type === "percent" ? "%" : "$";
  const baseRule =
    discountType === "%"
      ? `${Number(coupon.discount_value || 0)}% off`
      : `$${Number(coupon.discount_value || 0)} off`;

  const scope = coupon.applies_to_category
