    await Promise.resolve();
    await Promise.resolve();

    const qtyInput = wrapper.find("tbody input[type='number']");
    await qtyInput.setValue("1");
    await Promise.resolve();

    expect(api.quoteCommerceCart).toHaveBeenCalled();
