import { flushPromises, mount } from "@vue/test-utils";
import { beforeEach, describe, expect, test, vi } from "vitest";
import { createMemoryHistory, createRouter } from "vue-router";
import App from "../App.vue";
import { installRouteGuards, routes } from "../router.js";

const api = vi.hoisted(() => ({
  AUTH_TOKEN_KEY: "studio-auth-token",
  checkInReservation: vi.fn(),
  createEntity: vi.fn(),
  deleteEntity: vi.fn(),
  fetchAuditTrails: vi.fn(),
  fetchDailyReconciliation: vi.fn(),
  fetchList: vi.fn(),
  fetchReport: vi.fn(),
  fetchRoleDashboard: vi.fn(),
  fetchSecurityEvents: vi.fn(),
  fetchShiftReconciliation: vi.fn(),
  getCachedList: vi.fn(),
  markNoShows: vi.fn(),
  setCachedList: vi.fn(),
  submitShiftClose: vi.fn(),
  syncQueue: vi.fn(),
  clearStoredActorUserId: vi.fn(),
  clearStoredAuthToken: vi.fn(),
}));

vi.mock("../services/api.js", () => api);

function buildRouter() {
  const router = createRouter({
    history: createMemoryHistory(),
    routes,
  });
  installRouteGuards(router);
  return router;
}

describe("Entity flows e2e-style routing coverage", () => {
  beforeEach(() => {
    localStorage.clear();
    localStorage.setItem("studio-auth-token", "token-local");
    localStorage.setItem("studio-active-role", "manager");

    api.syncQueue.mockResolvedValue(undefined);
    api.fetchRoleDashboard.mockResolvedValue({
      dashboard: { title: "Dashboard", highlights: [] },
      permissions: [],
    });
    api.fetchReport.mockResolvedValue({});
    api.fetchList.mockResolvedValue({
      data: [{ id: "row-1", status: "booked" }],
      offline: false,
      forbidden: false,
    });
    api.createEntity.mockResolvedValue({ data: { id: "row-new" }, queued: false, forbidden: false });
    api.deleteEntity.mockResolvedValue({ queued: false, forbidden: false });
    api.getCachedList.mockReturnValue([]);
    api.setCachedList.mockImplementation(() => {});
    api.checkInReservation.mockResolvedValue({ forbidden: false, offline: false, data: { status: "checked_in" } });
    api.markNoShows.mockResolvedValue({ forbidden: false, offline: false, data: { marked_count: 0 } });
  });

  test("all required entity routes render dedicated views", async () => {
    const requiredRoutes = [
      "/reservations",
      "/orders",
      "/refunds",
      "/catalog-items",
      "/fines",
      "/audit-trails",
      "/users",
      "/resources",
    ];

    const router = buildRouter();
    await router.push(requiredRoutes[0]);
    await router.isReady();
    const wrapper = mount(App, {
      global: { plugins: [router] },
    });
    await flushPromises();

    for (const path of requiredRoutes) {
      await router.push(path);
      await flushPromises();
      expect(wrapper.find("h2").exists()).toBe(true);
    }
  });

  test("users route supports create and delete through full app shell", async () => {
    const router = buildRouter();
    await router.push("/users");
    await router.isReady();
    const wrapper = mount(App, {
      global: { plugins: [router] },
    });
    await flushPromises();

    const form = wrapper.find("form");
    expect(form.exists()).toBe(true);
    await form.trigger("submit.prevent");
    await flushPromises();
    expect(api.createEntity).toHaveBeenCalledWith("users", expect.any(Object));

    const deleteButton = wrapper
      .findAll("button")
      .find((node) => node.text().includes("Delete"));
    await deleteButton.trigger("click");
    await flushPromises();
    expect(api.deleteEntity).toHaveBeenCalledWith("users", "row-1");
  });
});

import { flushPromises, mount } from "@vue/test-utils";
import { beforeEach, describe, expect, test, vi } from "vitest";
import AuditTrailsPage from "../AuditTrailsPage.vue";
import CatalogItemsPage from "../CatalogItemsPage.vue";
import FinesPage from "../FinesPage.vue";
import OrdersPage from "../OrdersPage.vue";
import RefundsPage from "../RefundsPage.vue";
import ReservationsPage from "../ReservationsPage.vue";
import ResourcesPage from "../ResourcesPage.vue";
import UsersPage from "../UsersPage.vue";

const api = vi.hoisted(() => ({
  checkInReservation: vi.fn(),
  createEntity: vi.fn(),
  deleteEntity: vi.fn(),
  fetchList: vi.fn(),
  getCachedList: vi.fn(),
  markNoShows: vi.fn(),
  setCachedList: vi.fn(),
  syncQueue: vi.fn(),
}));

vi.mock("../../services/api.js", () => api);

const writeEnabledPages = [
  { name: "reservations", component: ReservationsPage, entity: "reservations" },
  { name: "orders", component: OrdersPage, entity: "orders" },
  { name: "refunds", component: RefundsPage, entity: "refunds" },
  { name: "catalog-items", component: CatalogItemsPage, entity: "catalog-items" },
  { name: "fines", component: FinesPage, entity: "fines" },
  { name: "users", component: UsersPage, entity: "users" },
  { name: "resources", component: ResourcesPage, entity: "resources" },
];

describe("Entity CRUD integration coverage", () => {
  beforeEach(() => {
    localStorage.clear();
    localStorage.setItem("studio-active-role", "manager");

    api.syncQueue.mockResolvedValue(undefined);
    api.checkInReservation.mockResolvedValue({
      data: { status: "checked_in" },
      forbidden: false,
      offline: false,
    });
    api.markNoShows.mockResolvedValue({
      data: { marked_count: 0 },
      forbidden: false,
      offline: false,
    });
    api.getCachedList.mockReturnValue([]);
    api.fetchList.mockResolvedValue({
      data: [{ id: "row-1", status: "booked" }],
      offline: false,
      forbidden: false,
    });
    api.createEntity.mockResolvedValue({
      data: { id: "row-new" },
      queued: false,
      forbidden: false,
    });
    api.deleteEntity.mockResolvedValue({ queued: false, forbidden: false });
  });

  for (const page of writeEnabledPages) {
    test(`${page.name} page supports load/create/delete flow`, async () => {
      const wrapper = mount(page.component);
      await flushPromises();

      expect(api.fetchList).toHaveBeenCalledWith(page.entity);

      const form = wrapper.find("form");
      expect(form.exists()).toBe(true);
      await form.trigger("submit.prevent");
      await flushPromises();

      expect(api.createEntity).toHaveBeenCalledWith(page.entity, expect.any(Object));

      const deleteButton = wrapper
        .findAll("button")
        .find((node) => node.text().includes("Delete"));
      expect(deleteButton).toBeTruthy();

      await deleteButton.trigger("click");
      await flushPromises();

      expect(api.deleteEntity).toHaveBeenCalledWith(page.entity, "row-1");
    });
  }

  test("audit trails page is read-only", async () => {
    const wrapper = mount(AuditTrailsPage);
    await flushPromises();

    expect(api.fetchList).toHaveBeenCalledWith("audit-trails");
    expect(wrapper.find("form").exists()).toBe(false);
    const deleteButton = wrapper
      .findAll("button")
      .find((node) => node.text().includes("Delete"));
    expect(deleteButton).toBeUndefined();
  });
});

import { flushPromises, mount } from "@vue/test-utils";
import { beforeEach, describe, expect, test, vi } from "vitest";
import UsersPage from "../UsersPage.vue";

const api = vi.hoisted(() => ({
  checkInReservation: vi.fn(),
  createEntity: vi.fn(),
  deleteEntity: vi.fn(),
  fetchList: vi.fn(),
  getCachedList: vi.fn(),
  markNoShows: vi.fn(),
  setCachedList: vi.fn(),
  syncQueue: vi.fn(),
}));

vi.mock("../../services/api.js", () => api);

describe("Entity offline and edge-state integration", () => {
  beforeEach(() => {
    localStorage.clear();
    localStorage.setItem("studio-active-role", "manager");

    api.syncQueue.mockResolvedValue(undefined);
    api.checkInReservation.mockResolvedValue({ forbidden: false, offline: false, data: { status: "checked_in" } });
    api.markNoShows.mockResolvedValue({ forbidden: false, offline: false, data: { marked_count: 0 } });
    api.getCachedList.mockReturnValue([{ id: "cached-1" }]);
    api.setCachedList.mockImplementation(() => {});
    api.createEntity.mockResolvedValue({ data: { id: "local-row" }, queued: true, forbidden: false });
    api.deleteEntity.mockResolvedValue({ queued: true, forbidden: false });
  });

  test("shows offline state and queued create/delete notices", async () => {
    api.fetchList.mockResolvedValue({
      data: [{ id: "row-1" }],
      offline: true,
      forbidden: false,
    });

    const wrapper = mount(UsersPage);
    await flushPromises();

    expect(wrapper.text()).toContain("Offline mode: showing cached records");

    await wrapper.find("form").trigger("submit.prevent");
    await flushPromises();
    expect(wrapper.text()).toContain("Saved to local queue");

    const deleteButton = wrapper
      .findAll("button")
      .find((node) => node.text().includes("Delete"));
    await deleteButton.trigger("click");
    await flushPromises();
    expect(wrapper.text()).toContain("Delete operation queued for later sync");
  });

  test("transitions from offline to online across reload", async () => {
    api.fetchList
      .mockResolvedValueOnce({
        data: [{ id: "row-offline" }],
        offline: true,
        forbidden: false,
      })
      .mockResolvedValueOnce({
        data: [{ id: "row-online" }],
        offline: false,
        forbidden: false,
      });

    const offlineWrapper = mount(UsersPage);
    await flushPromises();
    expect(offlineWrapper.text()).toContain("Offline mode: showing cached records");

    offlineWrapper.unmount();

    const onlineWrapper = mount(UsersPage);
    await flushPromises();
    expect(onlineWrapper.text()).not.toContain("Offline mode: showing cached records");
  });

  test("shows forbidden state for restricted access", async () => {
    api.fetchList.mockResolvedValue({ data: [], offline: false, forbidden: true });

    const wrapper = mount(UsersPage);
    await flushPromises();

    expect(wrapper.text()).toContain("Access is restricted for the active role");
  });
});

